import {
  SpeedDialItem,
  type SpeedDialItemData,
} from '@/components/azemmur/components/azemmur/speed-dial/speed-dial-item';
import { SpeedDialMenu } from '@/components/azemmur/components/azemmur/speed-dial/speed-dial-menu';
import { SpeedDialRoot } from '@/components/azemmur/components/azemmur/speed-dial/speed-dial-root';
import { SpeedDialTrigger } from '@/components/azemmur/components/azemmur/speed-dial/speed-dial-trigger';

type SpeedDialComponent = typeof SpeedDialRoot & {
  Trigger: typeof SpeedDialTrigger;
  Menu: typeof SpeedDialMenu;
  Item: typeof SpeedDialItem;
};

const SpeedDial = SpeedDialRoot as SpeedDialComponent;

SpeedDial.Trigger = SpeedDialTrigger;
SpeedDial.Menu = SpeedDialMenu;
SpeedDial.Item = SpeedDialItem;

export { SpeedDial, type SpeedDialItemData };

