'use client';

import { cn } from '@/lib/utils';
import { AnimatePresence, motion } from 'motion/react';
import { useSpeedDial } from '@/components/azemmur/components/azemmur/speed-dial/speed-dial-context';
import { speedDialMenuVariants } from '@/components/azemmur/components/azemmur/speed-dial/speed-dial-variants';

interface SpeedDialMenuProps {
  children: React.ReactNode;
  className?: string;
}

function SpeedDialMenu({ children, className }: SpeedDialMenuProps) {
  const { open, orientation, expansion, size } = useSpeedDial();

  return (
    <AnimatePresence>
      {open && (
        <motion.div
          id="speed-dial-menu"
          role="menu"
          aria-label="Speed dial actions"
          initial={{ opacity: 0, scale: 0.8 }}
          animate={{ opacity: 1, scale: 1 }}
          exit={{ opacity: 0, scale: 0.8 }}
          transition={{ duration: 0.15, ease: 'easeOut' }}
          className={cn(
            speedDialMenuVariants({ orientation, expansion, size }),
            className,
          )}
        >
          {children}
        </motion.div>
      )}
    </AnimatePresence>
  );
}

export { SpeedDialMenu, type SpeedDialMenuProps };

